/**
 * PayAI API Key JWT Authentication
 *
 * Provides Ed25519 (EdDSA) JWT generation for authenticating with the PayAI facilitator.
 * JWTs are used as Bearer tokens for credit-based access (bypassing free tier limits).
 *
 * Uses the Web Crypto API for zero-dependency, cross-runtime compatibility
 * (Node.js 18+, Edge runtimes, browsers).
 */
/**
 * Options for generating a PayAI API key JWT.
 */
interface PayAIJwtOptions {
    /** API Key ID (used as `kid` in JWT header and `sub` in payload) */
    apiKeyId: string;
    /**
     * API Key Secret (Ed25519 private key in PKCS#8/DER format, base64-encoded).
     *
     * Accepted formats:
     * - Raw base64: `"<base64>"`
     * - PayAI-prefixed (as shown in merchant portal): `"payai_sk_<base64>"`
     */
    apiKeySecret: string;
    /** JWT expiration in seconds (default: 120) */
    expiresIn?: number;
    /** Issuer claim (default: "payai-merchant") */
    issuer?: string;
}
/**
 * Get a cached JWT or generate a fresh one.
 *
 * Reuses the cached token until `REFRESH_BUFFER_SECONDS` before its expiry,
 * minimising signing operations while ensuring requests never use an expired token.
 *
 * @param options - JWT generation options
 * @returns JWT string (possibly from cache)
 */
declare function getOrGenerateJwt(options: PayAIJwtOptions): Promise<string>;
/**
 * Clear the JWT cache for a specific key, or all keys if none specified.
 *
 * @param apiKeyId - The API key ID to clear, or omit to clear all
 */
declare function clearJwtCache(apiKeyId?: string): void;
/**
 * Create a `createAuthHeaders` function compatible with `FacilitatorConfig`.
 *
 * Returns a function that generates `Authorization: Bearer <jwt>` headers
 * for every facilitator endpoint (verify, settle, supported). The JWT is
 * automatically cached and refreshed.
 *
 * @param apiKeyId - PayAI API Key ID
 * @param apiKeySecret - PayAI API Key Secret (raw base64 or `payai_sk_` prefixed)
 * @returns A function matching the `FacilitatorConfig.createAuthHeaders` signature
 */
declare function createPayAIAuthHeaders(apiKeyId: string, apiKeySecret: string): () => Promise<{
    verify: Record<string, string>;
    settle: Record<string, string>;
    supported: Record<string, string>;
}>;

/**
 * @module payai/facilitator
 *
 * Small, focused package for configuring the PayAI facilitator — mirroring
 * the design of `@coinbase/x402`. Merchants add one import and get a
 * ready-made `FacilitatorConfig` with automatic JWT authentication.
 *
 * @example
 * ```typescript
 * import { facilitator } from "@payai/facilitator";
 * import { HTTPFacilitatorClient } from "@x402/core/server";
 *
 * const client = new HTTPFacilitatorClient(facilitator);
 * // Done. Set PAYAI_API_KEY_ID + PAYAI_API_KEY_SECRET env vars for auth.
 * ```
 */
/**
 * Minimal facilitator client config shape used by `HTTPFacilitatorClient`.
 *
 * This intentionally mirrors `@x402/core/server`'s `FacilitatorConfig` *structurally*
 * without importing the type. That keeps `@payai/facilitator` usable in:
 * - v2 projects that already depend on `@x402/core` (recommended)
 * - v1 projects (x402-express/x402-next/x402-hono) that only want JWT header helpers
 * - custom clients (e.g. x402-solana) that don't otherwise install `@x402/core`
 */
interface FacilitatorConfig {
    url?: string;
    /**
     * Custom auth header factory. Called before every facilitator request.
     * Return per-endpoint headers (e.g. `Authorization: Bearer <jwt>`).
     */
    createAuthHeaders?: () => Promise<{
        verify: Record<string, string>;
        settle: Record<string, string>;
        supported: Record<string, string>;
    }>;
}
/**
 * Create a `FacilitatorConfig` for the PayAI facilitator.
 *
 * When API key credentials are provided (or available as env vars),
 * all facilitator requests are automatically authenticated with a JWT
 * Bearer token. The JWT is cached and refreshed transparently.
 *
 * @param apiKeyId - PayAI API Key ID (falls back to `PAYAI_API_KEY_ID` env var)
 * @param apiKeySecret - PayAI API Key Secret (falls back to `PAYAI_API_KEY_SECRET` env var)
 * @returns A `FacilitatorConfig` ready for `HTTPFacilitatorClient`
 *
 * @example
 * ```typescript
 * // Explicit credentials
 * const config = createFacilitatorConfig("my-key-id", "payai_sk_...");
 * const client = new HTTPFacilitatorClient(config);
 *
 * // Or let it read from env vars
 * const config = createFacilitatorConfig();
 * ```
 */
declare function createFacilitatorConfig(apiKeyId?: string, apiKeySecret?: string): FacilitatorConfig;
/**
 * Pre-built facilitator config that reads credentials from environment variables.
 *
 * Set `PAYAI_API_KEY_ID` and `PAYAI_API_KEY_SECRET` in your environment
 * to enable automatic JWT authentication. Without them, the config still
 * works (free tier, no auth).
 *
 * @example
 * ```typescript
 * import { facilitator } from "@payai/facilitator";
 * import { HTTPFacilitatorClient } from "@x402/core/server";
 *
 * const client = new HTTPFacilitatorClient(facilitator);
 * ```
 */
declare const facilitator: FacilitatorConfig;

export { type FacilitatorConfig, type PayAIJwtOptions, clearJwtCache, createFacilitatorConfig, createPayAIAuthHeaders, facilitator, getOrGenerateJwt };
